import{_ as E,C as n,o as a,c as s,a5 as t,b as i,w as r,a as A,E as l,a4 as d}from"./chunks/framework.gGRxziV4.js";const q=JSON.parse('{"title":"记忆与上下文","description":"","frontmatter":{},"headers":[],"relativePath":"03-Agent基础/03-记忆与上下文.md","filePath":"03-Agent基础/03-记忆与上下文.md","lastUpdated":1774181700000}'),B={name:"03-Agent基础/03-记忆与上下文.md"};function h(p,e,u,c,m,_){const o=n("Mermaid");return a(),s("div",null,[e[1]||(e[1]=t('<h1 id="记忆与上下文" tabindex="-1">记忆与上下文 <a class="header-anchor" href="#记忆与上下文" aria-label="Permalink to &quot;记忆与上下文&quot;">​</a></h1><blockquote><p>本章是 <strong>Hermes Engineering 系列</strong>第 3 模块的第 3 章。</p></blockquote><p>记忆系统让 Agent 从&quot;每次都是陌生人&quot;变成&quot;越用越懂你&quot;。但别指望它记住一切——向量相似度不是精确匹配，召回率和准确率需要取舍。</p><hr><h2 id="上下文窗口管理" tabindex="-1">上下文窗口管理 <a class="header-anchor" href="#上下文窗口管理" aria-label="Permalink to &quot;上下文窗口管理&quot;">​</a></h2><p>LLM 有一个叫&quot;上下文窗口&quot;的东西——Agent 的工作台。工作台能放多少东西取决于窗口大小。每个 Token 都是钱：50 轮对话约 25000 tokens 输入，每天 10 万个会话每月成本 $187,500。</p><p>上下文管理要解决四个互相矛盾的核心问题：超限（请求直接失败）、成本（历史越长越贵）、信息丢失（关键上下文被截掉）、噪音干扰（太多无关信息降低质量）。</p><h3 id="滑动窗口压缩" tabindex="-1">滑动窗口压缩 <a class="header-anchor" href="#滑动窗口压缩" aria-label="Permalink to &quot;滑动窗口压缩&quot;">​</a></h3><p>核心策略：保留重要的，压缩中间的。前 3 条（Primers）保留初始上下文建立，中间部分压缩成语义摘要，后 20 条（Recents）保持对话连贯。</p><p>触发时机：预算使用率 &gt;= 75% 时触发压缩，压到 37.5%。为什么 75%？留 25% 余量给当前轮。为什么 37.5%？压到一半以下留更多空间给后续对话。</p><h3 id="token-预算管理" tabindex="-1">Token 预算管理 <a class="header-anchor" href="#token-预算管理" aria-label="Permalink to &quot;Token 预算管理&quot;">​</a></h3><p>多层预算架构：Session 预算（整个会话总预算）→ Task 预算（单次任务）→ Agent 预算（单个 Agent）。分层让每个 Agent 都有自己的额度，不会相互挤占。</p><p>三种模式：硬限制（超预算直接拒绝，适合对外 API）、软限制（超预算发警告继续执行，适合内部工具）、审批模式（超预算暂停等人工确认，适合关键任务）。</p><p>背压机制：预算压力增大时不是突然停止，而是渐进式限流——使用率 80% 时轻微延迟，95% 时重度限流。</p><hr><h2 id="记忆架构" tabindex="-1">记忆架构 <a class="header-anchor" href="#记忆架构" aria-label="Permalink to &quot;记忆架构&quot;">​</a></h2><p>用户不会精确查询。用户问&quot;React 组件怎么优化？&quot;，存的可能是&quot;前端渲染性能提升方案&quot;。字符串完全不同但语义相关——这就是向量数据库的价值：按语义相似度检索而不是精确匹配。</p><h3 id="三层存储" tabindex="-1">三层存储 <a class="header-anchor" href="#三层存储" aria-label="Permalink to &quot;三层存储&quot;">​</a></h3>',18)),(a(),i(d,null,{default:r(()=>[l(o,{id:"mermaid-52",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20A%5B%E7%94%A8%E6%88%B7%E6%9F%A5%E8%AF%A2%5D%20--%3E%20B%7B%E9%9C%80%E8%A6%81%E4%BB%80%E4%B9%88%E6%95%B0%E6%8D%AE%EF%BC%9F%7D%0A%20%20%20%20B%20--%3E%7CACID%20%E4%BA%8B%E5%8A%A1%E6%95%B0%E6%8D%AE%3Cbr%2F%3E%E6%89%A7%E8%A1%8C%E5%8E%86%E5%8F%B2%2F%E5%AE%A1%E8%AE%A1%E6%97%A5%E5%BF%97%7C%20C%5BPostgreSQL%5D%0A%20%20%20%20B%20--%3E%7C%E7%83%AD%E6%95%B0%E6%8D%AE%E7%BC%93%E5%AD%98%3Cbr%2F%3E%E6%B4%BB%E8%B7%83%E4%BC%9A%E8%AF%9D%2FToken%E9%A2%84%E7%AE%97%7C%20D%5BRedis%3Cbr%2F%3E%E6%AF%AB%E7%A7%92%E7%BA%A7%5D%0A%20%20%20%20B%20--%3E%7C%E8%AF%AD%E4%B9%89%E7%9B%B8%E4%BC%BC%E5%BA%A6%E6%90%9C%E7%B4%A2%3Cbr%2F%3E%E5%8E%8B%E7%BC%A9%E6%91%98%E8%A6%81%2F%E6%96%87%E6%A1%A3%E5%88%86%E5%9D%97%7C%20E%5BQdrant%3Cbr%2F%3E%E5%90%91%E9%87%8F%E6%95%B0%E6%8D%AE%E5%BA%93%5D%0A%20%20%20%20C%20--%3E%20F%5B%E5%88%86%E5%B1%82%E8%AE%B0%E5%BF%86%E6%A3%80%E7%B4%A2%5D%0A%20%20%20%20D%20--%3E%20F%0A%20%20%20%20E%20--%3E%20F%0A%20%20%20%20F%20--%3E%20G%5BRecent%20%E6%9C%80%E8%BF%915%E6%9D%A1%5D%0A%20%20%20%20F%20--%3E%20H%5BSemantic%20%E8%AF%AD%E4%B9%89%E7%9B%B8%E5%85%B33%E6%9D%A1%5D%0A%20%20%20%20F%20--%3E%20I%5BSummary%20%E6%91%98%E8%A6%812%E6%9D%A1%5D%0A%20%20%20%20G%20--%3E%20J%5B%E4%B8%89%E5%B1%82%E5%8E%BB%E9%87%8D%E5%90%88%E5%B9%B6%5D%0A%20%20%20%20H%20--%3E%20J%0A%20%20%20%20I%20--%3E%20J%0A%20%20%20%20J%20--%3E%20K%5B%E8%BF%94%E5%9B%9E%E7%BB%99%20Agent%5D%0A"})]),fallback:r(()=>[...e[0]||(e[0]=[A(" Loading... ",-1)])]),_:1})),e[2]||(e[2]=t('<blockquote><p>💡 <strong>图解：</strong> 三层存储各司其职——PostgreSQL 管事务、Redis 管速度、Qdrant 管语义——缺一层就不完整。</p></blockquote><p><strong>PostgreSQL</strong>：需要 ACID 事务的数据——执行历史、审计日志、用户偏好。</p><p><strong>Redis</strong>：热数据缓存毫秒级访问——活跃会话、Token 预算、速率限制。</p><p><strong>Qdrant</strong>：向量相似度搜索——语义记忆、压缩摘要、文档分块。</p><p>另一种思路是本地文件存储（Claude Code 的 CLAUDE.md、Cursor 的 .cursor/ 目录）——零部署、版本控制友好、用户可读可编辑，但不适合多设备同步、语义检索弱、规模受限。</p><h3 id="语义检索" tabindex="-1">语义检索 <a class="header-anchor" href="#语义检索" aria-label="Permalink to &quot;语义检索&quot;">​</a></h3><p>核心流程：用户问题 → 生成 Embedding 向量 → 在向量数据库搜索相似向量 → 返回相关历史。</p><p>Embedding 把文本变成一串数字，语义相近的文本向量也相近。相似度阈值从 0.7 开始调——太高找不到太低返回垃圾。</p><h3 id="分层记忆检索" tabindex="-1">分层记忆检索 <a class="header-anchor" href="#分层记忆检索" aria-label="Permalink to &quot;分层记忆检索&quot;">​</a></h3><p>融合三种策略：Recent（最近 5 条保持对话连贯）+ Semantic（语义相关 3 条找历史中相关的）+ Summary（摘要 2 条快速建立长期上下文）。三层去重后返回。</p><h3 id="智能存储" tabindex="-1">智能存储 <a class="header-anchor" href="#智能存储" aria-label="Permalink to &quot;智能存储&quot;">​</a></h3><p>不是所有内容都值得存。去重（95% 相似度阈值）、长回答分块（2000 tokens 一块 200 tokens 重叠）、跳过低价值内容（太短、错误消息、闲聊）。</p><hr><h2 id="多轮对话设计" tabindex="-1">多轮对话设计 <a class="header-anchor" href="#多轮对话设计" aria-label="Permalink to &quot;多轮对话设计&quot;">​</a></h2><p>两级缓存架构：内存缓存（1ms）+ Redis 持久化（5ms）。热数据在内存冷数据落 Redis。</p><p>会话自动标题：用 LLM 从第一轮对话生成简短描述。PII 脱敏：存储前自动检测移除邮箱、电话、信用卡等敏感信息。租户隔离：不同租户记忆绝对不能互相访问，返回 ErrSessionNotFound 而不是 ErrUnauthorized。</p><hr><h2 id="本章要点" tabindex="-1">本章要点 <a class="header-anchor" href="#本章要点" aria-label="Permalink to &quot;本章要点&quot;">​</a></h2><ul><li>上下文窗口管理：三段式保留（Primers+Summary+Recents）+ 多层预算 + 背压</li><li>记忆三层存储：PostgreSQL（ACID）+ Redis（热缓存）+ Qdrant（语义检索）</li><li>分层检索：Recent + Semantic + Summary 三层融合去重</li><li>多轮对话：两级缓存、自动标题、PII 脱敏、租户隔离</li></ul><hr><p><strong>上一章</strong>: <a href="./02-工具与协议.html">工具与协议</a> | <strong>下一章</strong>: <a href="./04-高级推理.html">高级推理</a></p>',21))])}const b=E(B,[["render",h]]);export{q as __pageData,b as default};
